        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        autoCorrect: Boolean,
    ) {
        require(node.elementType == ANNOTATION_ENTRY)
        require(codeStyle == ktlint_official)
        require(node.primaryConstructorOrNull() != null)

        val prevLeaf = node.prevLeaf { !it.isWhiteSpace() }
        val hasMultipleAnnotations = node.isPrecededByOtherAnnotationEntry() || node.isFollowedByOtherAnnotationEntry()
        val hasAnnotationWithParameter = node.isAnnotationEntryWithValueArgumentList() ||
            node.treeParent.children().any { it.elementType == ANNOTATION_ENTRY && it.isAnnotationEntryWithValueArgumentList() }

        if (hasMultipleAnnotations || hasAnnotationWithParameter) {
            // In ktlint_official, when there are multiple annotations before constructor or any annotation has parameters,
            // each annotation should be on a separate line
            if (node.isFirstAnnotationEntry()) {
                // First annotation should be on a new line after the class name
                val prevLeafBeforeAnnotation = node.prevLeaf { !it.isWhiteSpace() }
                if (prevLeafBeforeAnnotation != null && !node.firstChildLeafOrSelf().prevLeaf().isWhiteSpaceWithNewline()) {
                    emit(
                        node.startOffset,
                        "Expected newline before annotation",
                        true,
                    )
                    if (autoCorrect) {
                        node
                            .firstChildLeafOrSelf()
                            .upsertWhitespaceBeforeMe(getNewlineWithIndent(node.treeParent).plus(indentConfig.indent))
                    }
                }
            }

            if (node.isPrecededByOtherAnnotationEntryOnTheSameLine()) {
                // Each annotation should be on its own line
                emit(
                    node.startOffset,
                    "Expected newline before annotation",
                    true,
                )
                if (autoCorrect) {
                    node
                        .firstChildLeafOrSelf()
                        .upsertWhitespaceBeforeMe(getNewlineWithIndent(node.treeParent).plus(indentConfig.indent))
                }
            }

            if (node.isLastAnnotationEntry() && node.isOnSameLineAsAnnotatedConstruct()) {
                // The constructor keyword should be on a new line after the last annotation
                emit(
                    node.findAnnotatedConstruct().startOffset,
                    "Expected newline before 'constructor' keyword",
                    true,
                )
                if (autoCorrect) {
                    node
                        .lastChildLeafOrSelf()
                        .nextCodeLeaf()
                        ?.upsertWhitespaceBeforeMe(getNewlineWithIndent(node.treeParent).plus(indentConfig.indent))
                }
            }
        }
    }

    private fun getNewlineWithIndent(modifierListRoot: ASTNode): String {
        val nodeBeforeAnnotations =
            modifierListRoot
                .treeParent
                .treePrev
        // Make sure we only insert a single newline
        val indentWithoutNewline =
            nodeBeforeAnnotations
                ?.text
                .orEmpty()
                .substringAfterLast('\n')
        return "\n".plus(indentWithoutNewline)
    }
}"}

