import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.ktlint_official
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test

class AnnotationRuleConstructorTest {
    private val annotationRuleAssertThat = assertThatRule { AnnotationRule() }

    @Nested
    inner class `Given ktlint_official code style` {
        @Test
        fun `Given a class with multiple annotations on constructor`() {
            val code =
                """
                data class Foo @Bar1 @Bar2("bar") @Bar3 @Bar4 constructor(private val foobar: Int) {
                    fun foo(): String = "foo"
                }
                """.trimIndent()
            val formattedCode =
                """
                data class Foo
                    @Bar1
                    @Bar2("bar")
                    @Bar3
                    @Bar4
                    constructor(private val foobar: Int) {
                    fun foo(): String = "foo"
                }
                """.trimIndent()
            annotationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
                .addAdditionalRuleProvider { IndentationRule() }
                .hasLintViolations(
                    LintViolation(1, 16, "Expected newline before annotation"),
                    LintViolation(1, 22, "Expected newline before annotation"),
                    LintViolation(1, 35, "Expected newline before annotation"),
                    LintViolation(1, 41, "Expected newline before annotation"),
                    LintViolation(1, 47, "Expected newline before 'constructor' keyword"),
                ).isFormattedAs(formattedCode)
        }

        @Test
        fun `Given a class with a single annotation with parameter on constructor`() {
            val code =
                """
                class Foo @Bar("bar") constructor(private val foobar: Int)
                """.trimIndent()
            val formattedCode =
                """
                class Foo
                    @Bar("bar")
                    constructor(private val foobar: Int)
                """.trimIndent()
            annotationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
                .addAdditionalRuleProvider { IndentationRule() }
                .hasLintViolations(
                    LintViolation(1, 11, "Expected newline before annotation"),
                    LintViolation(1, 23, "Expected newline before 'constructor' keyword"),
                ).isFormattedAs(formattedCode)
        }

        @Test
        fun `Given a class with a single annotation without parameter on constructor then do not change`() {
            val code =
                """
                class Foo @Inject internal constructor()
                """.trimIndent()
            annotationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
                .hasNoLintViolations()
        }

        @Test
        fun `Given a class with already wrapped annotations on constructor`() {
            val code =
                """
                data class Foo
                    @Bar1
                    @Bar2("bar")
                    @Bar3
                    @Bar4
                    constructor(private val foobar: Int) {
                    fun foo(): String = "foo"
                }
                """.trimIndent()
            annotationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
                .hasNoLintViolations()
        }
    }

    @Nested
    inner class `Given non-ktlint_official code style` {
        @Test
        fun `Given a class with multiple annotations on constructor in default style`() {
            val code =
                """
                class Foo @Inject internal constructor()
                """.trimIndent()
            annotationRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given a class with multiple annotations without params on constructor in default style`() {
            val code =
                """
                class Foo @Bar1 @Bar2 constructor()
                """.trimIndent()
            annotationRuleAssertThat(code).hasNoLintViolations()
        }
    }
}
